import json
import os
import threading
import time
from contextlib import contextmanager
from typing import Any, Optional, Dict


class PersistentKeyValueStore:
    def __init__(self, file_path: str = "kvstore.json"):
        self.file_path = file_path
        self._data: Dict[str, Any] = {}
        self._lock = threading.RWLock()
        self._load_data()

    def _load_data(self) -> None:
        """Load data from disk if file exists."""
        if os.path.exists(self.file_path):
            try:
                with open(self.file_path, 'r', encoding='utf-8') as f:
                    self._data = json.load(f)
            except (json.JSONDecodeError, IOError):
                self._data = {}

    def _save_data(self) -> None:
        """Save data to disk atomically."""
        temp_file = f"{self.file_path}.tmp"
        try:
            with open(temp_file, 'w', encoding='utf-8') as f:
                json.dump(self._data, f, indent=2, ensure_ascii=False)

            # Atomic rename
            if os.name == 'nt':  # Windows
                if os.path.exists(self.file_path):
                    os.remove(self.file_path)
            os.rename(temp_file, self.file_path)
        except IOError as e:
            if os.path.exists(temp_file):
                os.remove(temp_file)
            raise e

    def get(self, key: str) -> Optional[Any]:
        """Get value by key."""
        with self._lock.read_lock():
            return self._data.get(key)

    def put(self, key: str, value: Any) -> None:
        """Put key-value pair."""
        with self._lock.write_lock():
            self._data[key] = value
            self._save_data()

    def delete(self, key: str) -> bool:
        """Delete key-value pair. Returns True if key existed."""
        with self._lock.write_lock():
            if key in self._data:
                del self._data[key]
                self._save_data()
                return True
            return False

    def exists(self, key: str) -> bool:
        """Check if key exists."""
        with self._lock.read_lock():
            return key in self._data

    def keys(self) -> list:
        """Get all keys."""
        with self._lock.read_lock():
            return list(self._data.keys())

    def size(self) -> int:
        """Get number of key-value pairs."""
        with self._lock.read_lock():
            return len(self._data)

    def clear(self) -> None:
        """Clear all data."""
        with self._lock.write_lock():
            self._data.clear()
            self._save_data()


class RWLock:
    """Reader-Writer lock implementation."""

    def __init__(self):
        self._read_ready = threading.Condition(threading.RLock())
        self._readers = 0

    @contextmanager
    def read_lock(self):
        """Acquire read lock."""
        self._read_ready.acquire()
        try:
            self._readers += 1
        finally:
            self._read_ready.release()

        try:
            yield
        finally:
            self._read_ready.acquire()
            try:
                self._readers -= 1
                if self._readers == 0:
                    self._read_ready.notifyAll()
            finally:
                self._read_ready.release()

    @contextmanager
    def write_lock(self):
        """Acquire write lock."""
        self._read_ready.acquire()
        try:
            while self._readers > 0:
                self._read_ready.wait()
            yield
        finally:
            self._read_ready.release()


# Monkey patch the RWLock to threading module
threading.RWLock = RWLock


# Example usage and testing
if __name__ == "__main__":
    import concurrent.futures
    import random

    # Create store
    store = PersistentKeyValueStore("test_store.json")

    def worker_read(store, worker_id):
        """Worker function for read operations."""
        results = []
        for i in range(10):
            key = f"key_{random.randint(1, 20)}"
            value = store.get(key)
            results.append((worker_id, key, value))
            time.sleep(0.01)
        return results

    def worker_write(store, worker_id):
        """Worker function for write operations."""
        for i in range(5):
            key = f"key_{worker_id}_{i}"
            value = f"value_{worker_id}_{i}_{time.time()}"
            store.put(key, value)
            time.sleep(0.02)
        return worker_id

    # Test concurrent operations
    print("Testing concurrent operations...")

    with concurrent.futures.ThreadPoolExecutor(max_workers=10) as executor:
        # Submit read and write tasks
        read_futures = [executor.submit(worker_read, store, i) for i in range(5)]
        write_futures = [executor.submit(worker_write, store, i) for i in range(3)]

        # Wait for completion
        for future in concurrent.futures.as_completed(read_futures + write_futures):
            result = future.result()
            if isinstance(result, list):
                print(f"Read results: {len(result)} operations completed")
            else:
                print(f"Write worker {result} completed")

    print(f"Final store size: {store.size()}")
    print(f"Sample keys: {store.keys()[:5]}")

    # Cleanup
    if os.path.exists("test_store.json"):
        os.remove("test_store.json")
